"""Compare all 4 locale JSONs key structure and report missing keys.
Adds placeholder empty strings for missing keys in EN/NL/DE.
Handles arrays properly: compares semantic structure."""

import json, os, sys
from pathlib import Path

CONTENT_DIR = Path(__file__).resolve().parent.parent / 'content'
LOCALES = ['es', 'en', 'nl', 'de']

def get_semantic_keys(obj, prefix=''):
    """Get a set of dot-separated key paths, but for arrays use [*] as wildcard
    and only track structural keys, not individual indices."""
    keys = set()
    if isinstance(obj, dict):
        for k, v in obj.items():
            path = f'{prefix}.{k}' if prefix else k
            if isinstance(v, dict):
                keys.add(path)
                keys.update(get_semantic_keys(v, path))
            elif isinstance(v, list):
                keys.add(path)
                # Add [*] wildcard for array items
                if v:
                    # Get keys from first item as representative
                    first_item = v[0]
                    if isinstance(first_item, dict):
                        for fk in first_item.keys():
                            arr_path = f'{path}[*].{fk}'
                            keys.add(arr_path)
                            keys.update(get_semantic_keys(first_item[fk], arr_path))
                    elif isinstance(first_item, str):
                        keys.add(f'{path}[*]')
                else:
                    keys.add(f'{path}[*]')
            else:
                keys.add(path)
    elif isinstance(obj, list):
        for item in obj:
            if isinstance(item, dict):
                keys.update(get_semantic_keys(item, prefix))
    return keys

def fill_missing_semantic(target, reference, prefix=''):
    """Fill missing keys in target based on reference structure."""
    if not isinstance(target, dict):
        return target

    result = dict(target)

    for k, v in reference.items():
        path = f'{prefix}.{k}' if prefix else k

        if isinstance(v, dict):
            if k not in result:
                result[k] = fill_missing_semantic({}, v, path)
            elif isinstance(result[k], dict):
                result[k] = fill_missing_semantic(result[k], v, path)
            elif isinstance(result[k], list):
                # Keep arrays as-is
                pass
        elif isinstance(v, list):
            if k not in result:
                result[k] = []
        else:
            if k not in result:
                result[k] = ''

    return result

def main():
    # Load all files
    locales = {}
    for loc in LOCALES:
        path = CONTENT_DIR / f'{loc}.json'
        with open(path, 'r', encoding='utf-8') as f:
            locales[loc] = json.load(f)

    # Get reference keys from ES
    es_keys = get_semantic_keys(locales['es'])

    report_lines = []
    report_lines.append('=== LOCALE KEY COMPARISON REPORT ===')
    report_lines.append(f'Spanish (es) semantic keys: {len(es_keys)}')
    report_lines.append('')

    all_ok = True

    for loc in ['en', 'nl', 'de']:
        loc_keys = get_semantic_keys(locales[loc])
        missing_in_loc = es_keys - loc_keys
        extra_in_loc = loc_keys - es_keys

        report_lines.append(f'--- {loc.upper()} ({loc}) ---')
        report_lines.append(f'  Semantic keys: {len(loc_keys)}')
        report_lines.append(f'  Missing vs ES: {len(missing_in_loc)}')

        if missing_in_loc:
            report_lines.append('  Missing keys:')
            for k in sorted(missing_in_loc):
                report_lines.append(f'    - {k}')
        else:
            report_lines.append('  No missing keys!')

        if extra_in_loc:
            report_lines.append(f'  Extra keys (not in ES): {len(extra_in_loc)}')
            for k in sorted(extra_in_loc):
                report_lines.append(f'    + {k}')
        else:
            report_lines.append('  No extra keys.')

        report_lines.append('')

        if missing_in_loc:
            all_ok = False
            # Fill missing keys with empty strings using semantic structure
            locales[loc] = fill_missing_semantic(locales[loc], locales['es'])

            # Save
            out_path = CONTENT_DIR / f'{loc}.json'
            with open(out_path, 'w', encoding='utf-8') as f:
                json.dump(locales[loc], f, indent=2, ensure_ascii=False)
            report_lines.append(f'  >>> Filled missing keys with empty strings in {loc}.json')
        else:
            report_lines.append(f'  >>> No changes needed for {loc}.json')
        report_lines.append('')

    # Verify post-fix
    report_lines.append('=== POST-FIX VERIFICATION ===')
    for loc in ['en', 'nl', 'de']:
        path = CONTENT_DIR / f'{loc}.json'
        with open(path, 'r', encoding='utf-8') as f:
            fixed = json.load(f)
        fixed_keys = get_semantic_keys(fixed)
        still_missing = es_keys - fixed_keys
        extra_keys = fixed_keys - es_keys
        if still_missing:
            report_lines.append(f'{loc}: STILL MISSING {len(still_missing)} semantic keys!')
            for k in sorted(still_missing):
                report_lines.append(f'  - {k}')
        else:
            report_lines.append(f'{loc}: All semantic keys match ES. OK.')
        if extra_keys:
            report_lines.append(f'{loc}: Extra semantic keys: {len(extra_keys)}')
            for k in sorted(extra_keys):
                report_lines.append(f'  + {k}')

    report_text = '\n'.join(report_lines)
    print(report_text)

    report_path = CONTENT_DIR / 'locale-key-comparison-report.txt'
    with open(report_path, 'w', encoding='utf-8') as f:
        f.write(report_text)
    print(f'\nReport written to {report_path}')

if __name__ == '__main__':
    main()
