"""Compare locale JSONs at semantic key level and fill missing keys with ''."""
import json
from pathlib import Path

CONTENT_DIR = Path(__file__).resolve().parent.parent / 'content'
LOCALES = ['es', 'en', 'nl', 'de']

def load_json(path):
    with open(path, 'r', encoding='utf-8') as f:
        return json.load(f)

def save_json(path, data):
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)

def get_semantic_keys(obj, prefix=''):
    """Get dot-separated key paths. For arrays tracks [*] with representative fields."""
    keys = set()
    if isinstance(obj, dict):
        for k, v in obj.items():
            path = f'{prefix}.{k}' if prefix else k
            if isinstance(v, dict):
                keys.add(path)
                keys.update(get_semantic_keys(v, path))
            elif isinstance(v, list):
                keys.add(path)
                if v and isinstance(v[0], dict):
                    for fk in v[0]:
                        arr_path = f'{path}[*].{fk}'
                        arr_val = v[0][fk]
                        keys.add(arr_path)
                        if isinstance(arr_val, dict):
                            keys.update(get_semantic_keys(arr_val, arr_path))
                        elif isinstance(arr_val, list):
                            keys.add(f'{arr_path}[*]')
            else:
                keys.add(path)
    return keys

def ensure_path(obj, path_parts):
    """Ensure a nested path exists in obj, creating empty dicts/'' as needed. Returns the target."""
    current = obj
    for i, part in enumerate(path_parts):
        if part == '*' and isinstance(current, list):
            if not current:
                current.append({})
            current = current[0]
        elif isinstance(current, dict):
            if part not in current:
                if i == len(path_parts) - 1:
                    current[part] = ''
                else:
                    next_part = path_parts[i+1]
                    if next_part == '*':
                        current[part] = []
                    else:
                        current[part] = {}
            current = current[part]
        elif isinstance(current, list):
            # We're at an array but need a dict key
            if not current:
                current.append({})
            current = current[0]
            if part not in current:
                if i == len(path_parts) - 1:
                    current[part] = ''
                else:
                    next_part = path_parts[i+1]
                    if next_part == '*':
                        current[part] = []
                    else:
                        current[part] = {}
            current = current[part]
    return current

def fill_missing_keys(target, reference):
    """Fill missing keys in target based on reference structure."""
