{"content": "#!/usr/bin/env python3
"""Add specific missing keys to EN/NL/DE locale JSONs.
Only adds keys that exist in ES but not in other locales.
For simple string keys: adds '' placeholder.
For dict keys: adds {} placeholder.
For array keys: adds [] placeholder."""

import json
from pathlib import Path

CONTENT_DIR = Path(__file__).resolve().parent.parent / 'content'
LOCALES = ['es', 'en', 'nl', 'de']

def load_json(path):
    with open(path, 'r', encoding='utf-8') as f:
        return json.load(f)

def save_json(path, data):
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)

def get_scalar_keys(obj, prefix=''):
    """Get all leaf key paths (only those ending in scalars/strings)."""
    keys = set()
    if isinstance(obj, dict):
        for k, v in obj.items():
            path = f'{prefix}.{k}' if prefix else k
            if isinstance(v, dict):
                keys.update(get_scalar_keys(v, path))
            elif isinstance(v, list):
                keys.add(f'{path}[]')
            else:
                keys.add(path)
    return keys

def get_obj_at(data, path):
    """Navigate to a nested object given a dot-separated path."""
    parts = path.split('.')
    current = data
    for p in parts:
        if isinstance(current, dict):
            if p not in current:
                return None
            current = current[p]
        else:
            return None
    return current

def set_obj_at(data, path, value):
    """Set a value at a nested path, creating intermediate dicts if needed."""
    parts = path.split('.')
    current = data
    for i, p in enumerate(parts):
        if i == len(parts) - 1:
            current[p] = value
        else:
            if p not in current or not isinstance(current[p], dict):
                current[p] = {}
            current = current[p]

# Determine what's missing
es = load_json(CONTENT_DIR / 'es.json')
es_scalar = get_scalar_keys(es)

for loc in ['en', 'nl', 'de']:
    data = load_json(CONTENT_DIR / f'{loc}.json')
    loc_scalar = get_scalar_keys(data)

    missing_scalar = es_scalar - loc_scalar
    # Filter to only scalar keys (not ending with [])
    missing_scalar = {k for k in missing_scalar if not k.endswith('[]')}

    missing_arrays = {k for k in (es_scalar - loc_scalar) if k.endswith('[]')}

    print(f'\n=== {loc.upper()} ===')

    # Add missing scalar keys as ''
    added_count = 0
    for key in sorted(missing_scalar):
        # Check if parent exists
        parts = key.split('.')
        parent_path = '.'.join(parts[:-1])
        parent = get_obj_at(data, parent_path) if parent_path else data
        if parent is None:
            print(f'  SKIP {key} - parent path {parent_path} does not exist')
            continue
        if isinstance(parent, dict) and parts[-1] not in parent:
            parent[parts[-1]] = ''
            added_count += 1
            print(f'  Added: {key} = ""')

    # Add missing array keys as []
    for key in sorted(missing_arrays):
        clean_key = key[:-2]  # Remove '[]'
        parts = clean_key.split('.')
        parent_path = '.'.join(parts[:-1])
        parent = get_obj_at(data, parent_path) if parent_path else data
        if parent is None:
            print(f'  SKIP {key} - parent path {parent_path} does not exist')
            continue
        if isinstance(parent, dict) and parts[-1] not in parent:
            # Determine what ES has for this array
            es_arr = get_obj_at(es, clean_key)
            if es_arr and len(es_arr) > 0 and isinstance(es_arr[0], dict):
                # Create one sample item with empty strings
                sample = {k: '' for k in es_arr[0].keys()}
                parent[parts[-1]] = [sample]
                added_count += 1
                print(f'  Added: {clean_key} = [{{...}}] (from ES template)')
            else:
                parent[parts[-1]] = []
                added_count += 1
                print(f'  Added: {clean_key} = []')

    print(f'  Total additions: {added_count}')

    if added_count > 0:
        save_json(CONTENT_DIR / f'{loc}.json', data)
        print(f'  Saved {loc}.json')
    else:
        print(f'  No changes needed.')

# Final verification
print('\n=== VERIFICATION ===')
es_scalar = get_scalar_keys(load_json(CONTENT_DIR / 'es.json'))
for loc in ['en', 'nl', 'de']:
    data = load_json(CONTENT_DIR / f'{loc}.json')
    loc_s = get_scalar_keys(data)
    still_missing = es_scalar - loc_s
    if still_missing:
        print(f'{loc}: {len(still_missing)} keys still missing:')
        for k in sorted(still_missing):
            print(f'  - {k}')
    else:
        print(f'{loc}: All keys present.')
